hold_ticks := 0
if ((#Door #Kitchen).door_doorState == "open") {
hold_ticks = hold_ticks + 1
    if (hold_ticks >= 6000) {
(#Plug #Switch #Kitchen #Fan).switch_on()
        break
}
}
else {
hold_ticks = 0
}

